WHERE w.work_usage = 'Y' AND w.work_order_qty > 0 AND w.work_fdate IS NOT NULL
AND w.work_date >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND w.work_date >= ADD_MONTHS(TRUNC(SYSDATE + (9/24)), -6)
AND w.work_date < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1
AND (
) = #{workStatus}
AND TO_CHAR(i.item_type) = #{itemType}
AND ( UPPER(w.work_id) LIKE UPPER('%' || #{itemKeyword} || '%') OR UPPER(w.work_plan) LIKE UPPER('%' || #{itemKeyword} || '%') OR UPPER(p.plan_id) LIKE UPPER('%' || #{itemKeyword} || '%') OR UPPER(i.item_id) LIKE UPPER('%' || #{itemKeyword} || '%') OR UPPER(i.item_name) LIKE UPPER('%' || #{itemKeyword} || '%') OR UPPER(d.emp_name) LIKE UPPER('%' || #{itemKeyword} || '%') OR UPPER(worker.emp_name) LIKE UPPER('%' || #{itemKeyword} || '%') )
